22	// serviceRunFactory, when non-nil, overrides NewServiceFromWorkDir inside
23	// RunWithConfigViaService. CLI-level integration tests inject a stub to
24	// observe ServiceExecuteRequest fields without a real agent server.
25	var serviceRunFactory func(workDir string) (agentlib.FizeauService, error)
26	
27	// fizeauHarness maps DDx internal harness names to the Fizeau wire contract.
28	// "agent" is DDx's internal name for the embedded native harness; Fizeau
29	// v0.10.12+ uses "fiz" as the native harness identity on its wire API.
30	func fizeauHarness(name string) string {
31		if name == "agent" {
32			return "fiz"
33		}
34		return name
35	}
