37	// SetServiceRunFactory installs a service factory for RunWithConfigViaService.
38	// Pass nil to restore production behavior. Exported for cmd/ integration tests.
39	//
40	// Production reachability: invoked from init() with nil so the symbol is
41	// reachable from main() under deadcode RTA. Real overrides come from cmd/
42	// integration tests at test-setup time.
43	func SetServiceRunFactory(f func(workDir string) (agentlib.FizeauService, error)) {
44		serviceRunFactory = f
45	}
46	
47	func init() {
48		// Reach SetServiceRunFactory from main() so it survives deadcode RTA.
49		// The nil reset is a no-op: production never sets the factory.
50		SetServiceRunFactory(nil)
51	}
