87	// RunWithConfigViaService dispatches a single agent invocation through the
88	// agent service. It takes a sealed ResolvedConfig (durable knobs) and an
89	// AgentRunRuntime (per-invocation plumbing/intent), and is the SD-024
90	// successor to the retired RunViaService/RunViaServiceWith entry points.
91	//
92	// The virtual and script harnesses route through a DDx-owned Runner path,
93	// not the upstream service. These are not "carve-outs pending migration" —
94	// they are different products from upstream's same-named stubs. DDx's
95	// virtual is a content-addressed record/replay dictionary keyed by
96	// PromptHash; upstream's is a unit-test stub where callers stuff
97	// virtual.response into Metadata. DDx's script reads a filesystem directive
98	// file; upstream does not model this at all.
99	func RunWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
100		if ctx == nil {
101			ctx = context.Background()
102		}
103	
104		harness := rcfg.Passthrough().Harness
105	
106		effectivePerms := runtime.PermissionsOverride
107		if effectivePerms == "" {
108			effectivePerms = rcfg.Permissions()
109		}
110		if err := ValidateReadOnlyReviewerDispatch(harness, effectivePerms); err != nil {
111			return nil, err
112		}
113	
114		if harness == "virtual" || harness == "script" {
115			sessionLogDir := runtime.SessionLogDirOverride
116			if sessionLogDir == "" {
117				sessionLogDir = rcfg.SessionLogDir()
118			}
119			cfg := Config{SessionLogDir: ResolveLogDir(workDir, "")}
120			r := NewRunner(cfg)
121			r.WorkDir = workDir
122			return r.runInternal(RunArgs{
123				Context:       ctx,
124				Harness:       rcfg.Harness(),
125				Prompt:        runtime.Prompt,
126				PromptFile:    runtime.PromptFile,
127				PromptSource:  runtime.PromptSource,
128				Correlation:   runtime.Correlation,
129				Model:         rcfg.Model(),
130				Provider:      rcfg.Provider(),
131				Effort:        rcfg.Effort(),
132				Timeout:       rcfg.Timeout(),
133				WallClock:     rcfg.WallClock(),
134				WorkDir:       runtime.WorkDir,
135				Permissions:   rcfg.Permissions(),
136				SessionLogDir: sessionLogDir,
137				Env:           runtime.Env,
138			})
139		}
140	
141		svc, err := resolveService(workDir)
142		if err != nil {
143			return nil, fmt.Errorf("agent: build service: %w", err)
144		}
145		return executeOnService(ctx, svc, workDir, rcfg, runtime)
146	}
