148	// executeOnService dispatches against a pre-built svc using the durable
149	// knobs from rcfg and per-invocation plumbing from runtime, then records
150	// one session-index row. It is the inlined replacement for the retired
151	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
152	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
153		if svc == nil {
154			return nil, fmt.Errorf("agent: nil service")
155		}
156		if ctx == nil {
157			ctx = context.Background()
158		}
159	
160		promptText := runtime.Prompt
161		if runtime.PromptFile != "" {
162			data, err := readPromptFileBounded(runtime.PromptFile)
163			if err != nil {
164				return nil, fmt.Errorf("agent: read prompt file: %w", err)
165			}
166			promptText = string(data)
167		}
168		if promptText == "" {
169			return nil, fmt.Errorf("agent: prompt is required")
170		}
171	
172		wd := runtime.WorkDir
173		if wd == "" {
174			wd = workDir
175		}
176		if wd == "" {
177			wd, _ = os.Getwd()
178		}
179	
180		idle := rcfg.Timeout()
181		if idle <= 0 {
182			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
183		}
184		wall := rcfg.WallClock()
185		if wall <= 0 {
186			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
187		}
188	
189		sessionLogDir := runtime.SessionLogDirOverride
190		if sessionLogDir == "" {
191			sessionLogDir = rcfg.SessionLogDir()
192		}
193		if sessionLogDir == "" {
194			sessionLogDir = ResolveLogDir(workDir, "")
195		}
196	
197		pt := rcfg.Passthrough()
198	
199		harness := runtime.HarnessOverride
200		if harness == "" && !runtime.ClearRoutingPins {
201			harness = pt.Harness
202		}
203	
204		model := runtime.ModelOverride
205		if model == "" && !runtime.ClearRoutingPins {
206			model = pt.Model
207		}
208	
209		provider := runtime.ProviderOverride
210		if provider == "" && !runtime.ClearRoutingPins {
211			provider = pt.Provider
212		}
213		if runtime.ClearRoutingPins && runtime.ProviderOverride == "" {
214			provider = ""
215		}
216	
217		profile := runtime.ProfileOverride
218		if profile == "" && !runtime.ClearProfile {
219			profile = rcfg.Profile()
220		}
221	
222		permissions := runtime.PermissionsOverride
223		if permissions == "" {
224			permissions = rcfg.Permissions()
225		}
226	
227		providerTimeout := ResolveProviderRequestTimeout(workDir, provider, model, rcfg.ProviderRequestTimeout())
228	
229		minPower := rcfg.MinPower()
230		if runtime.MinPowerOverride > 0 {
231			minPower = runtime.MinPowerOverride
232		}
233		if runtime.ClearMinPower {
234			minPower = 0
235		}
236		maxPower := rcfg.MaxPower()
237		if runtime.ClearMaxPower {
238			maxPower = 0
239		}
240		if minPower > 0 && maxPower > 0 && minPower >= maxPower {
241			return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
242		}
243	
244		req := agentlib.ServiceExecuteRequest{
245			Prompt:          promptText,
246			Model:           model,
247			Policy:          profile,
248			Provider:        provider,
249			Harness:         fizeauHarness(harness),
250			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
251			Permissions:     permissions,
252			WorkDir:         wd,
253			Timeout:         wall,
254			IdleTimeout:     idle,
255			ProviderTimeout: providerTimeout,
256			SessionLogDir:   sessionLogDir,
257			Metadata:        metadataWithEnv(runtime.Correlation, runtime.Env),
258			Role:            runtime.Role,
259			CorrelationID:   runtime.CorrelationID,
260			MinPower:        minPower,
261			MaxPower:        maxPower,
262		}
263		seedRecentRouteAttemptsFromTracker(ctx, svc, workDir, time.Now().UTC())
264	
265		cancelCtx, cancel := context.WithCancel(ctx)
266		defer cancel()
267	
268		// When Harness is set and Model is empty, fizeau routes within the harness's
269		// eligible models using Profile/MinPower as the routing constraint. This is the
270		// well-formed request shape for profile-driven dispatch without an explicit model.
271		// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
272		// errors and a failed final event for post-dispatch errors.
273		start := time.Now().UTC()
274		events, err := svc.Execute(cancelCtx, req)
275		if err != nil {
276			return nil, fmt.Errorf("agent: execute: %w", err)
277		}
278	
279		workPhase := strings.TrimSpace(runtime.WorkLogPhase)
280		if workPhase == "" {
281			workPhase = "do"
282		}
283		renderer := NewWorkLogRenderer(WorkLogRendererOptions{
284			CurrentBeadID: runtime.Correlation["bead_id"],
285			WorkPhase:     workPhase,
286		})
287		watchdog := &drainWatchdog{
288			cancel:          cancel,
289			idleTimeout:     idle,
290			toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
291		}
292		final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer, watchdog)
293		finishedAt := time.Now().UTC()
294		elapsed := finishedAt.Sub(start)
295	
296		result := &Result{
297			Harness:    fizeauHarness(harness),
298			Model:      model,
299			DurationMS: int(elapsed.Milliseconds()),
300		}
301		if routing != nil {
302			result.Provider = routing.Provider
303			if routing.Model != "" {
304				result.Model = routing.Model
305			}
306			if routing.Harness != "" {
307				result.Harness = routing.Harness
308			}
309			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
310				result.PredictedPower = power
311				result.PredictedSpeedTPS = speed
312				result.PredictedCostUSDPer1kTokens = cost
313				result.PredictedCostSource = source
314			}
315		}
316		if final != nil {
317			// Normalized final text from the upstream harness (agent-32e8ff5e);
318			// reviewer verdict extraction now parses this instead of raw stream
319			// frames (ddx-7bc0c8d5).
320			result.Output = final.FinalText
321			if final.Usage != nil {
322				// v0.9.1: Usage fields became *int (nullable).
323				if final.Usage.InputTokens != nil {
324					result.InputTokens = *final.Usage.InputTokens
325				}
326				if final.Usage.OutputTokens != nil {
327					result.OutputTokens = *final.Usage.OutputTokens
328				}
329				if final.Usage.TotalTokens != nil {
330					result.Tokens = *final.Usage.TotalTokens
331				}
332			}
333			if final.CostUSD > 0 {
334				result.CostUSD = final.CostUSD
335			}
336			result.ExitCode = final.ExitCode
337			result.Error = final.Error
338			if final.RoutingActual != nil {
339				if result.Provider == "" {
340					result.Provider = final.RoutingActual.Provider
341				}
342				if final.RoutingActual.Model != "" {
343					result.Model = final.RoutingActual.Model
344				}
345				if final.RoutingActual.Harness != "" {
346					result.Harness = final.RoutingActual.Harness
347				}
348				if final.RoutingActual.Power > 0 {
349					result.ActualPower = final.RoutingActual.Power
350				}
351			}
352			if final.SessionLogPath != "" {
353				result.AgentSessionID = final.SessionLogPath
354			}
355		}
356		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
357		normalizeServiceFinalExitCode(result)
358		recordServiceRouteAttempt(ctx, svc, result, elapsed, finishedAt)
359		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
360			Harness:     harness,
361			Model:       model,
362			Provider:    provider,
363			Effort:      rcfg.Effort(),
364			Correlation: runtime.Correlation,
365		}, result, start, finishedAt)
366		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
367		return result, nil
368	}
