370	func seedRecentRouteAttemptsFromTracker(ctx context.Context, svc agentlib.FizeauService, projectRoot string, now time.Time) {
371		if svc == nil || strings.TrimSpace(projectRoot) == "" {
372			return
373		}
374		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
375		beads, err := store.List("", "", nil)
376		if err != nil {
377			return
378		}
379		cutoff := now.Add(-ProviderUnavailableCooldown)
380		seen := map[string]struct{}{}
381		for _, b := range beads {
382			for _, failed := range readFailedRoutes(b.Extra) {
383				at, _ := time.Parse(time.RFC3339, strings.TrimSpace(failed.At))
384				if at.IsZero() {
385					at = now
386				}
387				if at.Before(cutoff) || at.After(now.Add(time.Minute)) || strings.TrimSpace(failed.Provider) == "" {
388					continue
389				}
390				key := "\x00" + failed.Provider + "\x00" + failed.Model
391				if _, ok := seen[key]; ok {
392					continue
393				}
394				seen[key] = struct{}{}
395				_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
396					Provider:  failed.Provider,
397					Model:     failed.Model,
398					Status:    "failed",
399					Reason:    FailureModeProviderConnectivity,
400					Error:     FailureModeProviderConnectivity,
401					Timestamp: at,
402				})
403			}
404			events, err := store.Events(b.ID)
405			if err != nil {
406				continue
407			}
408			for _, ev := range events {
409				if ev.Kind != "route-failure" || ev.CreatedAt.Before(cutoff) || ev.CreatedAt.After(now.Add(time.Minute)) {
410					continue
411				}
412				var body map[string]any
413				if err := json.Unmarshal([]byte(ev.Body), &body); err != nil {
414					continue
415				}
416				if strings.TrimSpace(fmt.Sprint(body["outcome_reason"])) != FailureModeProviderConnectivity {
417					continue
418				}
419				provider := strings.TrimSpace(fmt.Sprint(body["provider"]))
420				if provider == "" || provider == "<nil>" {
421					continue
422				}
423				harness := strings.TrimSpace(fmt.Sprint(body["harness"]))
424				model := strings.TrimSpace(fmt.Sprint(body["model"]))
425				key := harness + "\x00" + provider + "\x00" + model
426				if _, ok := seen[key]; ok {
427					continue
428				}
429				seen[key] = struct{}{}
430				_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
431					Harness:   harness,
432					Provider:  provider,
433					Model:     model,
434					Status:    "failed",
435					Reason:    FailureModeProviderConnectivity,
436					Error:     strings.TrimSpace(fmt.Sprint(body["error"])),
437					Timestamp: ev.CreatedAt,
438				})
439			}
440		}
441	}
