443	func recordServiceRouteAttempt(ctx context.Context, svc agentlib.FizeauService, result *Result, elapsed time.Duration, finishedAt time.Time) {
444		if svc == nil || result == nil || strings.TrimSpace(result.Provider) == "" {
445			return
446		}
447		status := "success"
448		reason := "success"
449		if result.ExitCode != 0 || strings.TrimSpace(result.Error) != "" {
450			status = "failed"
451			reason = "execution_failed"
452			if strings.TrimSpace(result.Error) != "" {
453				reason = "provider_error"
454			}
455		}
456		_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
457			Harness:   result.Harness,
458			Provider:  result.Provider,
459			Model:     result.Model,
460			Status:    status,
461			Reason:    reason,
462			Error:     result.Error,
463			Duration:  elapsed,
464			Timestamp: finishedAt,
465		})
466	}
