468	func metadataWithEnv(metadata, env map[string]string) map[string]string {
469		if len(metadata) == 0 && len(env) == 0 {
470			return nil
471		}
472		out := make(map[string]string, len(metadata)+len(env))
473		for k, v := range metadata {
474			out[k] = v
475		}
476		for k, v := range env {
477			out[k] = v
478		}
479		return out
480	}
