491	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
492	// querying the service's ListHarnesses and (best-effort) the harness registry.
493	// It is the production replacement for Runner.Capabilities.
494	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
495		if ctx == nil {
496			ctx = context.Background()
497		}
498		svc, err := resolveService(workDir)
499		if err != nil {
500			return nil, fmt.Errorf("agent: build service: %w", err)
501		}
502		infos, err := svc.ListHarnesses(ctx)
503		if err != nil {
504			return nil, fmt.Errorf("agent: list harnesses: %w", err)
505		}
506		var info *agentlib.HarnessInfo
507		for i := range infos {
508			if infos[i].Name == harnessName {
509				info = &infos[i]
510				break
511			}
512		}
513		if info == nil {
514			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
515		}
516	
517		// Pull binary and reasoning-level metadata from the local registry — the
518		// service does not expose these directly today.
519		registry := newHarnessRegistry()
520		harness, _ := registry.Get(harnessName)
521	
522		caps := &HarnessCapabilities{
523			Harness:             info.Name,
524			Available:           info.Available,
525			Binary:              harness.Binary,
526			Path:                info.Path,
527			Surface:             harness.Surface,
528			CostClass:           info.CostClass,
529			IsLocal:             info.CostClass == "local",
530			ExactPinSupport:     info.ExactPinSupport,
531			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
532			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
533		}
534		if len(info.SupportedReasoning) > 0 {
535			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
536		} else if len(harness.ReasoningLevels) > 0 {
537			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
538		}
539	
540		if harness.DefaultModel != "" {
541			caps.Model = harness.DefaultModel
542			caps.Models = []string{harness.DefaultModel}
543		}
544	
545		return caps, nil
546	}
