548	// TestProviderConnectivityViaService runs a HealthCheck against the named
549	// harness and translates the result into a ProviderStatus. It is the
550	// production replacement for Runner.TestProviderConnectivity.
551	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
552		status := ProviderStatus{Reachable: false}
553		if ctx == nil {
554			ctx = context.Background()
555		}
556		if harnessName == "virtual" || harnessName == "agent" {
557			status.Reachable = true
558			status.CreditsOK = true
559			return status
560		}
561		svc, err := resolveService(workDir)
562		if err != nil {
563			status.Error = err.Error()
564			return status
565		}
566		if timeout > 0 {
567			var cancel context.CancelFunc
568			ctx, cancel = context.WithTimeout(ctx, timeout)
569			defer cancel()
570		}
571		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
572			errStr := strings.ToLower(err.Error())
573			status.Error = err.Error()
574			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
575				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
576				status.CreditsOK = false
577			}
578			return status
579		}
580		status.Reachable = true
581		status.CreditsOK = true
582		return status
583	}
