585	// ValidateForExecuteLoopViaService is the production replacement for
586	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
587	// will pick at claim time). When harness is specified it confirms the harness
588	// exists in the service registry and (when model is set) attempts a
589	// ResolveRoute pre-flight.
590	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider string) error {
591		if harnessName == "" {
592			return nil
593		}
594		if ctx == nil {
595			ctx = context.Background()
596		}
597		svc, err := resolveService(workDir)
598		if err != nil {
599			return fmt.Errorf("agent: build service: %w", err)
600		}
601		infos, err := svc.ListHarnesses(ctx)
602		if err != nil {
603			return fmt.Errorf("agent: list harnesses: %w", err)
604		}
605		found := false
606		for _, info := range infos {
607			if info.Name == harnessName {
608				found = true
609				if !info.Available {
610					return fmt.Errorf("agent: harness %s not available", harnessName)
611				}
612				break
613			}
614		}
615		if !found {
616			return fmt.Errorf("agent: unknown harness: %s", harnessName)
617		}
618	
619		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
620		// model is provided and provider is not set.
621		if model != "" && provider == "" && harnessName == "agent" {
622			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
623				Model:    model,
624				Harness:  fizeauHarness(harnessName),
625				Provider: provider,
