633	// ValidateEffortForRunViaService rejects effort requests that no currently
634	// available harness can satisfy. `legacy agent run` passes effort through to the
635	// service rather than resolving a route locally, but the command still needs a
636	// fast failure for obviously impossible combinations so operators get a useful
637	// error instead of a silent success path.
638	func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
639		if effort == "" {
640			return nil
641		}
642		if ctx == nil {
643			ctx = context.Background()
644		}
645		svc, err := resolveService(workDir)
646		if err != nil {
647			return fmt.Errorf("agent: build service: %w", err)
648		}
649		infos, err := svc.ListHarnesses(ctx)
650		if err != nil {
651			return fmt.Errorf("agent: list harnesses: %w", err)
652		}
653		registry := newHarnessRegistry()
654		for _, info := range infos {
655			if !info.Available {
656				continue
657			}
658			if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
659				return nil
660			}
661		}
662		if profile == "" {
663			return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
664		}
665		return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
666	}
