123	// TestPassthroughEnvelope_InvariantUnderPowerEscalation (AC3): bumping MinPower
124	// does not mutate harness/provider/model in the passthrough.
125	func TestPassthroughEnvelope_InvariantUnderPowerEscalation(t *testing.T) {
126		rcfg := resolvedWithPassthrough("claude", "anthropic", "claude-3-5-sonnet", 0, 0)
127		pt := rcfg.Passthrough()
