129		// Simulate retry escalation: produce a new ResolvedConfig with higher MinPower
130		// but the same harness/provider/model. The passthrough must stay the same.
131		escalated := resolvedWithPassthrough("claude", "anthropic", "claude-3-5-sonnet", 50, 100)
132		ptEscalated := escalated.Passthrough()
133	
134		if ptEscalated.Harness != pt.Harness {
135			t.Errorf("Harness changed under escalation: got %q, want %q", ptEscalated.Harness, pt.Harness)
136		}
137		if ptEscalated.Provider != pt.Provider {
138			t.Errorf("Provider changed under escalation: got %q, want %q", ptEscalated.Provider, pt.Provider)
139		}
140		if ptEscalated.Model != pt.Model {
141			t.Errorf("Model changed under escalation: got %q, want %q", ptEscalated.Model, pt.Model)
142		}
143	
144		// MaxPower must be preserved too.
145		if escalated.MaxPower() != 100 {
146			t.Errorf("MaxPower should be 100 after escalation, got %d", escalated.MaxPower())
147		}
148		if escalated.MinPower() != 50 {
149			t.Errorf("MinPower should be 50 after escalation, got %d", escalated.MinPower())
150		}
151	}
