16	// Attempt records availability feedback for one routed attempt.
17	type Attempt struct {
18		Harness   string
19		Provider  string
20		Model     string
21		Endpoint  string
22		Status    string
23		Reason    string
24		Error     string
25		Duration  time.Duration
