189	func endpointProviderEntry(endpoint ddxconfig.AgentEndpoint, index int) (string, agentlib.ServiceProviderEntry, error) {
190		providerType := strings.ToLower(strings.TrimSpace(endpoint.Type))
191		baseURL := strings.TrimSpace(endpoint.BaseURL)
192		if baseURL == "" {
193			if endpoint.Host == "" || endpoint.Port == 0 {
194				return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: base_url or host+port is required", index)
195			}
196			baseURL = fmt.Sprintf("http://%s:%d/v1", endpoint.Host, endpoint.Port)
197		}
198		if providerType == "" {
199			providerType = inferEndpointProviderType(baseURL, endpoint.Port)
200		}
201		if providerType == "" {
202			return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: type is required when it cannot be inferred", index)
203		}
204	
205		name := endpointProviderName(providerType, baseURL, endpoint, index)
206		billing, includeByDefault := endpointRoutingDefaults(providerType)
207		return name, agentlib.ServiceProviderEntry{
208			Type:                providerType,
209			BaseURL:             baseURL,
210			APIKey:              endpoint.APIKey,
211			Billing:             billing,
212			IncludeByDefault:    includeByDefault,
213			IncludeByDefaultSet: true,
214		}, nil
215	}
