217	func endpointRoutingDefaults(providerType string) (agentlib.BillingModel, bool) {
218		switch strings.ToLower(strings.TrimSpace(providerType)) {
219		case "lmstudio", "omlx", "ollama", "vllm", "rapid-mlx", "llama-server":
220			return agentlib.BillingModelFixed, true
221		default:
222			return agentlib.BillingModelUnknown, false
223		}
224	}
