226	func inferEndpointProviderType(baseURL string, port int) string {
227		low := strings.ToLower(baseURL)
228		switch {
229		case strings.Contains(low, "openrouter.ai"):
230			return "openrouter"
231		case strings.Contains(low, "openai.com"):
232			return "openai"
233		case strings.Contains(low, ":1235") || port == 1235:
234			return "omlx"
235		case strings.Contains(low, ":11434") || port == 11434:
236			return "ollama"
237		case strings.Contains(low, ":1234") || port == 1234:
238			return "lmstudio"
239		default:
240			return ""
241		}
242	}
243	
244	func endpointProviderName(providerType, baseURL string, endpoint ddxconfig.AgentEndpoint, index int) string {
245		host := endpoint.Host
246		port := endpoint.Port
247		if u, err := url.Parse(baseURL); err == nil {
248			if host == "" {
249				host = u.Hostname()
250			}
251			if port == 0 {
252				if p := u.Port(); p != "" {
253					if n, err := strconv.Atoi(p); err == nil {
254						port = n
255					}
256				}
257			}
258		}
259		parts := []string{providerType}
260		if host != "" {
261			parts = append(parts, host)
262		}
263		if port != 0 {
264			parts = append(parts, strconv.Itoa(port))
265		}
266		if len(parts) == 1 {
267			parts = append(parts, strconv.Itoa(index+1))
268		}
269		return sanitizeEndpointName(strings.Join(parts, "-"))
270	}
271	
272	func sanitizeEndpointName(s string) string {
273		s = strings.ToLower(strings.TrimSpace(s))
274		var b strings.Builder
275		lastDash := false
276		for _, r := range s {
277			keep := unicode.IsLetter(r) || unicode.IsDigit(r)
278			if keep {
279				b.WriteRune(r)
280				lastDash = false
281				continue
282			}
283			if !lastDash {
284				b.WriteByte('-')
285				lastDash = true
286			}
287		}
288		out := strings.Trim(b.String(), "-")
289		if out == "" {
290			return "endpoint"
291		}
292		return out
293	}
